/**
 * Generate Coresignal firewall config.
 *
 * Data source: https://docs.coresignal.com/api-introduction/authorization
 *
 * Coresignal uses an API key passed in the `apikey` request header.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.coresignal.com/api-introduction/authorization";
// Format: 32 alphanumeric chars
const PLACEHOLDER_VALUE = "Coffee5afe10ca1Coffee5afe10ca1Co";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Coresignal API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:coresignal",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const coresignalFirewall = {",
    '  name: "coresignal",',
    '  description: "Coresignal API",',
    "  placeholders: {",
    `    CORESIGNAL_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.coresignal.com",',
    "      auth: {",
    "        headers: {",
    '          apikey: "${{ secrets.CORESIGNAL_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Coresignal firewall config...");
  const ts = generateTypeScript();
  writeOutput("coresignal", ts, import.meta.dirname);
}
